import React from "react";
import { useNavigate } from "react-router-dom";
import { useSelector } from "react-redux";
import { Dropdown } from "react-bootstrap";
import { PersonGear } from "react-bootstrap-icons";

const AdminNav = ({ setDrawer }) => {
  const navigate = useNavigate();
  const inst = useSelector((state) => state.inst.activeInst);
  return (
    <>
      <Dropdown style={{ width: "100%" }}>
        <Dropdown.Toggle variant="transparent" className="nav-link">
          <PersonGear /> Admin{" "}
        </Dropdown.Toggle>
        <Dropdown.Menu variant="dark">
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                setDrawer(false);
                navigate(`staffs`);
              }}
            >
              Staffs
            </p>
          </Dropdown.Item>
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                setDrawer(false);
                navigate(`modes`);
              }}
            >
              Payment Modes
            </p>
          </Dropdown.Item>
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                setDrawer(false);
                navigate(`owners`);
              }}
            >
              Property Owners
            </p>
          </Dropdown.Item>
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                setDrawer(false);
                navigate(`buildings`);
              }}
            >
              Buildings/Hostels
            </p>
          </Dropdown.Item>
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                setDrawer(false);
                navigate(`bills`);
              }}
            >
              Bills
            </p>
          </Dropdown.Item>
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                setDrawer(false);
                navigate(`expensecats`);
              }}
            >
              Expense Categories
            </p>
          </Dropdown.Item>
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                setDrawer(false);
                navigate(`expenses`);
              }}
            >
              Expenses
            </p>
          </Dropdown.Item>{" "}
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                setDrawer(false);
                navigate(`edit`);
              }}
            >
              Edit Institution
            </p>
          </Dropdown.Item>
        </Dropdown.Menu>
      </Dropdown>
      <hr />
    </>
  );
};

export default AdminNav;
