import React, { useState, useEffect } from "react";
import { Outlet } from "react-router-dom";
import AdminNav from "../Admin/AdminNav";
import { useSelector } from "react-redux";
import {
  Bank,
  BarChartLine,
  Cash,
  HouseDoor,
  People,
  PersonCircle,
  ReceiptCutoff,
  Globe,
  Mailbox,
} from "react-bootstrap-icons";
import { useNavigate } from "react-router-dom";
import { VerifySub } from "../../Utils/VerifySub";
import SocketMessages from "../../Utils/SocketMessages";
import FetchData from "../../Utils/FetchData";
import Header from "../../components/Header";

const Dashboard = () => {
  const navigate = useNavigate();
  const inst = useSelector((state) => state.inst.activeInst);
  const User = useSelector((state) => state.auth.user);
  const subs = useSelector((state) => state.sub.subs);
  const ActiveCred = useSelector((state) => state.cred.activeCred);
  const Sub = VerifySub(subs, ActiveCred.instLinker);
  const [Drawer, setDrawer] = useState(false);

  const ToggleDrawer = () => setDrawer(!Drawer);

  useEffect(() => {
    if (!ActiveCred.linker) {
      navigate("/");
    }
  }, []);

  return (
    <>
      <Header ToggleDrawer={ToggleDrawer}></Header>
      <div style={{ marginTop: "40px" }}>
        <SocketMessages></SocketMessages>
        <FetchData></FetchData>

        <div className="d-flex">
          <div
            className={`bg-secondary ${
              Drawer ? "side-menu-open" : "side-menu"
            }`}
          >
            <div>
              <p
                onClick={() => {
                  setDrawer(false);
                  navigate(`/${inst.name}`);
                }}
              >
                <strong className="nav-link text-truncate">
                  <Bank /> {inst.name}
                </strong>
              </p>
              <hr />
              <p
                onClick={() => {
                  setDrawer(false);
                  navigate(`profile`);
                }}
              >
                <strong className="nav-link text-truncate">
                  <PersonCircle /> {User.name || User.logger}
                </strong>
              </p>
              <hr />
              {parseInt(ActiveCred.admin) === 1 && Sub > 0 ? (
                <AdminNav setDrawer={setDrawer}></AdminNav>
              ) : null}
              {(parseInt(ActiveCred.admin) === 1 ||
                parseInt(ActiveCred.staff) === 1) &&
              Sub > 0 ? (
                <>
                  <p
                    onClick={() => {
                      setDrawer(false);
                      navigate(`houses`);
                    }}
                  >
                    <strong className="nav-link text-truncate">
                      <HouseDoor /> Houses/Rooms
                    </strong>
                  </p>
                  <hr />
                  <p
                    onClick={() => {
                      setDrawer(false);
                      navigate(`tenants`);
                    }}
                  >
                    <strong className="nav-link text-truncate">
                      <People /> Tenants
                    </strong>
                  </p>
                  <hr />
                  <p
                    onClick={() => {
                      setDrawer(false);
                      navigate(`invoices`);
                    }}
                  >
                    <strong className="nav-link text-truncate">
                      <ReceiptCutoff /> Invoices
                    </strong>
                  </p>
                  <hr />
                  <p
                    onClick={() => {
                      setDrawer(false);
                      navigate(`payments`);
                    }}
                  >
                    <strong className="nav-link text-truncate">
                      <Cash /> Payments
                    </strong>
                  </p>
                  <hr />
                  <p
                    onClick={() => {
                      setDrawer(false);
                      navigate(`monthly-report`);
                    }}
                  >
                    <strong className="nav-link text-truncate">
                      <BarChartLine /> Monthly Report
                    </strong>
                  </p>
                  <hr />
                </>
              ) : null}
            </div>
            <p>
              {Sub - 30 * 24 * 60 * 60 < 0 &&
              parseInt(ActiveCred.admin) === 1 ? (
                <span
                  onClick={() =>
                    navigate(
                      `/${inst.name}/activate/${inst.name}/${inst.clientId}`
                    )
                  }
                  className="text-center"
                  style={{
                    color: "hotpink",
                    cursor: "pointer",
                  }}
                >
                  <small>Activate </small>
                </span>
              ) : null}{" "}
              <br />
              <span
                onClick={() => navigate(`/${inst.name}/terms`)}
                className="text-center text-info"
                style={{
                  cursor: "pointer",
                  fontSize: "12px",
                }}
              >
                <small>Terms And Conditions </small>
              </span>{" "}
              <br />
              <span
                onClick={() => navigate(`/${inst.name}/privacy`)}
                className="text-center text-info"
                style={{
                  cursor: "pointer",
                  fontSize: "12px",
                }}
              >
                <small>Privacy Policy </small>
              </span>{" "}
              <br />
              <span
                className="text-center text-light"
                style={{
                  cursor: "pointer",
                  fontSize: "12px",
                }}
              >
                <small>
                  <Globe /> www.techsystems.world
                </small>
              </span>
              <br />
              <span
                className="text-center text-light"
                style={{
                  cursor: "pointer",
                  fontSize: "12px",
                }}
              >
                <small>
                  <Mailbox /> info@techsystems.world
                </small>
              </span>
              <br />
              <span
                className="text-center text-light"
                style={{
                  cursor: "pointer",
                  fontSize: "12px",
                }}
              >
                <small>&copy; {new Date().getFullYear()} Techsystems</small>
              </span>
            </p>
          </div>
          <div
            className={`${
              Drawer ? "main-page-drawer-open" : "main-page-drawer-closed"
            }`}
          >
            {" "}
            {Sub < 0 ? (
              <>
                {subs.length > 0 ? (
                  <p className="text-danger text-center h6">
                    Annual Period Lapsed{" "}
                    {parseInt(ActiveCred.admin) === 1 ? (
                      <span
                        className="text-primary btn-link"
                        style={{ cursor: "pointer" }}
                        onClick={() =>
                          navigate(
                            `/${inst.name}/activate/${inst.name}/${inst.clientId}`
                          )
                        }
                      >
                        <em>Click To Activate</em>
                      </span>
                    ) : (
                      "Contact Your Institution Admin to Activate"
                    )}
                  </p>
                ) : (
                  <p className="text-danger text-center h6">
                    Trial Period Lapsed{" "}
                    {parseInt(ActiveCred.admin) === 1 ? (
                      <span
                        className="text-primary btn-link"
                        style={{ cursor: "pointer" }}
                        onClick={() =>
                          navigate(
                            `/${inst.name}/activate/${inst.name}/${inst.clientId}`
                          )
                        }
                      >
                        <em>Click To Activate</em>
                      </span>
                    ) : (
                      "Contact Your Institution Admin to Activate"
                    )}
                  </p>
                )}
              </>
            ) : Sub < 5 * 24 * 60 * 60 ? (
              <>
                {subs.length > 0 ? (
                  <p className="text-danger text-center h6">
                    Annual Period Lapsing in {parseInt(Sub / (24 * 60 * 60))}{" "}
                    Days
                    {parseInt(ActiveCred.admin) === 1 ? (
                      <span
                        className="text-primary btn-link"
                        style={{ cursor: "pointer" }}
                        onClick={() =>
                          navigate(
                            `/${inst.name}/activate/${inst.name}/${inst.clientId}`
                          )
                        }
                      >
                        <em>Click To Activate</em>
                      </span>
                    ) : (
                      "Contact Your Institution Admin to Activate"
                    )}
                  </p>
                ) : (
                  <p className="text-danger text-center h6">
                    Trial Period Lapsing In {parseInt(Sub / (24 * 60 * 60))}{" "}
                    Days
                    {parseInt(ActiveCred.admin) === 1 ? (
                      <span
                        className="text-primary btn-link"
                        style={{ cursor: "pointer" }}
                        onClick={() =>
                          navigate(
                            `/${inst.name}/activate/${inst.name}/${inst.clientId}`
                          )
                        }
                      >
                        <em>Click To Activate</em>
                      </span>
                    ) : (
                      "Contact Your Institution Admin to Activate"
                    )}
                  </p>
                )}
              </>
            ) : null}
            <div className="bg-light">
              {Sub > 0 ? <Outlet></Outlet> : <></>}
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default Dashboard;
